    content: none;
  }

  .hero-light {
    display: none;
  }

  .hero-head {
    position: relative;
    z-index: 2;
    text-align: center;
  }

  .section-kicker {
    display: inline-flex;
    align-items: center;
    gap: 7px;
    color: rgba(255,255,255,.82);
    font-size: clamp(11px, .9vw, 14px);
    letter-spacing: -.02em;
  }

  .section-kicker span {
    width: 7px;
    height: 7px;
    border-left: 1px solid rgba(255,255,255,.7);
    border-top: 1px solid rgba(255,255,255,.7);
  }

  .section-kicker span:last-child { transform: rotate(180deg); }

  .hero-head h1 {
    margin: 18px 0 0;
    font-size: clamp(48px, 6.6vw, 94px);
    line-height: 1.03;
    letter-spacing: -.06em;
